            hx-encoding="multipart/form-data"
            hx-on::after-request="this.querySelector('input[name=text]').value=''; this.querySelector('input[name=voice_input]').value=''; var ii=this.querySelector('input[name=image]'); if(ii) ii.value=''; var pv=this.querySelector('.benson-image-preview'); if(pv) pv.innerHTML=''; document.getElementById('chat-log-full').scrollTop = 9e9; this.querySelector('input[name=text]').focus(); bensonSaveChatHistory();">
