          <button type="button" class="btn btn-outline-warning btn-lg benson-attach-btn" title="Attach image (or paste from clipboard)">📎</button>
          <input type="text" name="text" class="form-control form-control-lg benson-text-input"
                 placeholder="Ask Benson… (or paste an image)" autofocus autocomplete="off">
          <button class="btn btn-warning btn-lg" type="submit">
            Send <span class="htmx-indicator">…</span>
          </button>
        </div>
      </form>

Note: remove the `required` attribute from the text input so a message with only an image (no text) can be submitted.


--- STEP 3: Add {% block scripts %} at the end of the file, before {% endblock %} ---

At the very end of the file, before the final {% endblock %}, add:

{% block scripts %}
<script>
(function(){
  var STORAGE_KEY = 'benson_chat_full_history';
  var log = document.getElementById('chat-log-full');
  var form = document.querySelector('.benson-chat-form');

  // --- Restore persisted history on load ---
  var saved = localStorage.getItem(STORAGE_KEY);
  if (saved && log) {
    // Remove the placeholder hint text (first child div.text-secondary) if history exists
    var hint = log.querySelector('div.text-secondary.small.text-center');
    if (hint) hint.remove();
    log.innerHTML = saved;
    log.scrollTop = 9e9;
  }

  // --- Save history helper (called from hx-on::after-request) ---
  window.bensonSaveChatHistory = function() {
    if (log) {
      // Strip the hint div if still present before saving
      var hint = log.querySelector('div.text-secondary.small.text-center');
      if (hint) hint.remove();
      localStorage.setItem(STORAGE_KEY, log.innerHTML);
    }
  };

  // --- Clear button ---
  var clearBtn = document.getElementById('chat-clear-btn');
  if (clearBtn) {
    clearBtn.addEventListener('click', function() {
      localStorage.removeItem(STORAGE_KEY);
      if (log) {
        log.innerHTML = '<div class="text-secondary small text-center my-4">' +
          'Ask Benson anything. He can answer questions about the house, ' +
          'control fans / lights / shades / Sonos, and pull up recipes.<br>' +
          'Try: <em>"turn off the master bedroom fan light"</em>, ' +
          '<em>"what chores does Zander have today?"</em>, ' +
          '<em>"open the shades"</em>.<br>' +
          '<strong>🎙 Click the mic to talk</strong> — Benson replies on your room\'s speaker.' +
          '</div>';
      }
    });
  }

  // --- Attach button + file picker ---
  if (form) {
    var attachBtn = form.querySelector('.benson-attach-btn');
    var fileInput = form.querySelector('.benson-image-input');
    var textInput = form.querySelector('.benson-text-input');
    var preview   = form.querySelector('.benson-image-preview');

    function showPreview(file) {
      if (!file || !preview) { if (preview) preview.innerHTML = ''; return; }
      var url = URL.createObjectURL(file);
      preview.innerHTML =
        '<div class="d-flex align-items-center gap-2 mt-1">' +
        '  <img src="' + url + '" style="max-height:48px;max-width:80px;border-radius:4px;border:1px solid #444">' +
        '  <span>' + (file.name || 'pasted image') + ' (' + Math.round(file.size/1024) + ' KB)</span>' +
        '  <button type="button" class="btn btn-sm btn-outline-secondary" style="padding:0 .4rem">×</button>' +
        '</div>';
      preview.querySelector('button').addEventListener('click', function() {
        fileInput.value = '';
        preview.innerHTML = '';
      });
    }

    if (attachBtn && fileInput) {
      attachBtn.addEventListener('click', function() { fileInput.click(); });
      fileInput.addEventListener('change', function() {
        showPreview(fileInput.files && fileInput.files[0]);
      });
    }

    // Clipboard paste — intercept image items
    if (textInput) {
      textInput.addEventListener('paste', function(e) {
        var items = (e.clipboardData || {}).items || [];
        for (var i = 0; i < items.length; i++) {
          var it = items[i];
          if (it.kind === 'file' && it.type.indexOf('image/') === 0) {
            var blob = it.getAsFile();
            if (!blob) continue;
            var dt = new DataTransfer();
            dt.items.add(blob);
            fileInput.files = dt.files;
            showPreview(blob);
            e.preventDefault();
            break;
          }
        }
      });
    }
  }

  // --- Speaker/room selects: sync hidden fields (mirrors layout.html logic) ---
  var speakerSel = document.querySelector('.benson-speaker-select');
  var roomSel    = document.querySelector('.benson-room-select');
  function syncHidden() {
    document.querySelectorAll('.benson-chat-form').forEach(function(f) {
      var sp = f.querySelector('input[name=speaker]');
      var rm = f.querySelector('input[name=room]');
      if (sp) sp.value = speakerSel ? speakerSel.value : 'Casey';
      if (rm) rm.value = roomSel ? roomSel.value : 'hub';
    });
  }
  if (speakerSel) {
    speakerSel.value = localStorage.getItem('benson_speaker') || 'Casey';
    speakerSel.addEventListener('change', function() {
      localStorage.setItem('benson_speaker', speakerSel.value);
      syncHidden();
    });
  }
  if (roomSel) {
    roomSel.value = localStorage.getItem('benson_room') || 'hub';
    roomSel.addEventListener('change', function() {
      localStorage.setItem('benson_room', roomSel.value);
      syncHidden();
    });
  }
  syncHidden();

  // --- Mic button (Web Speech API) ---
  var SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  var micBtns = document.querySelectorAll('.benson-mic-btn');
  if (!SR) {
    micBtns.forEach(function(b) { b.disabled = true; b.title = 'Speech recognition not available in this browser'; });
  } else {
    micBtns.forEach(function(btn) {
      var rec = null;
      var listening = false;
      btn.addEventListener('click', function() {
        if (listening) { rec.stop(); return; }
        rec = new SR();
        rec.lang = 'en-US';
        rec.interimResults = false;
        rec.maxAlternatives = 1;
        rec.continuous = false;
        var theForm = btn.closest('form');
        var ti = theForm.querySelector('input[name=text]');
        var vf = theForm.querySelector('input[name=voice_input]');
        rec.onstart = function() {
          listening = true;
          btn.classList.add('btn-danger'); btn.classList.remove('btn-outline-warning');
          btn.textContent = '● rec';
        };
        rec.onresult = function(e) {
          var txt = e.results[0][0].transcript.trim();
          ti.value = txt;
          vf.value = '1';
          if (typeof htmx !== 'undefined') htmx.trigger(theForm, 'submit');
          else theForm.submit();
        };
        rec.onerror = function(e) { console.warn('SR error', e); };
        rec.onend = function() {
          listening = false;
          btn.classList.add('btn-outline-warning'); btn.classList.remove('btn-danger');
          btn.textContent = '🎙️';
        };
        rec.start();
      });
    });
  }
})();
</script>
{% endblock %}


--- NOTES FOR THE CODING SESSION ---
- Only edit middleware/templates/chat.html. Do not touch layout.html, hub.py, or any other file.
- The existing speaker/room select logic in layout.html's inline script also runs on this page (it's part of the layout). The new scripts block on chat.html should NOT re-declare competing handlers for those selects — it should just initialize their values from localStorage and wire up syncHidden as a standalone function scoped to this page (the layout.html code uses querySelectorAll('.benson-speaker-select') which will pick up the ones on this page too, but since this page has its own selects, we wire them here as well). Actually the safest approach: skip re-wiring speaker/room in the {% block scripts %} section entirely since layout.html's inline script already does it globally via querySelectorAll. Only keep the attach/paste/preview/clear/history/mic code in the block scripts section.
- The `required` attribute on the text input should be removed so image-only submissions work.
- Test that the localStorage key "benson_chat_full_history" stores innerHTML and restores on reload.
- The clear button should restore the original placeholder hint text exactly.
